const aiItem = $input.item.json;
const aiResponse = aiItem.output || aiItem.text || aiItem.response || '';
let ads = [];

// SAFE NODE REFERENCING
let prevData = { main_image: '', title: '' };
try {
    // Try standard selector
    prevData = $('Extract & Normalize').first().json;
} catch(e) {
    try {
        // Try $node selector (legacy)
        if ($node['Extract & Normalize']) {
            prevData = $node['Extract & Normalize'].json;
        }
    } catch(e2) {}
}

if (aiItem.error) {
    // Handle Execution Error
    const errDetail = aiItem.error.message || aiItem.error.description || JSON.stringify(aiItem.error);
    ads = [{ type: 'Error', headline: 'AI Connection Failed', primary_text: 'Debug: ' + errDetail + ' (Mixtral 8x7b)', image_prompt: 'N/A' }];
} else {
    try {
         if (typeof aiResponse === 'string') {
            // STRICT JSON EXTRACTOR
            // Find first [ and last ]
            const jsonMatch = aiResponse.match(/\[[\s\S]*\]/);
            if (jsonMatch) {
                ads = JSON.parse(jsonMatch[0]);
            } else {
                // Try full parse if no brackets found
                const cleanJson = aiResponse.replace(/```json/g, '').replace(/```/g, '').trim();
                ads = JSON.parse(cleanJson);
            }
         } else {
            ads = Array.isArray(aiResponse) ? aiResponse : [aiResponse];
         }
    } catch (e) {
         ads = [{ type: 'Error', headline: 'Parse Error', primary_text: 'Raw Response: ' + aiResponse.substring(0, 100), image_prompt: 'N/A' }];
    }
}

return {
    ads: ads,
    product_image: prevData.main_image || '',
    product_title: prevData.title || ''
};
